import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);

  // Davis trigger: ex.params.event | Manual trigger: ex.params.event.params
  const event = ex.params?.event || {};
  const src   = event?.params || event || {};
  console.log('event data:', JSON.stringify(event));

  // Escapa cualquier valor para insertarlo de forma segura dentro del JSON del payload
  const esc = (s) => JSON.stringify(String(s == null ? '' : s)).slice(1, -1);

  const severity  = src['problem.severityLevel'] || event['event.category'] || 'OTHER';
  const problemId = src['problem.id'] || event['display_id'] || 'P-MANUAL-TEST';
  const title     = src['problem.title'] || event['event.name'] || 'Manual Test';
  const detTime   = src['problem.detectionTime'] || event['event.start'] || new Date().toISOString();
  const url       = src['problem.url'] || '';

  const displayId     = event['display_id'] || problemId;
  const description   = event['event.description'] || '';
  const affectedNames = (event['affected_entity_names'] || []).join(', ');
  const affectedTypes = (event['affected_entity_types'] || []).join(', ');
  const impactLevel   = (event['dt.davis.impact_level'] || [])[0] || '';
  const hostName      = (event['host.name'] || [])[0] || '';
  const hostGroup     = (event['dt.host_group.id'] || [])[0] || '';

  const tags = event['entity_tags'] || [];
  const getTag = (prefix) => {
    const p = prefix.toUpperCase();
    const match = tags.find(t => t.toUpperCase().startsWith(p + ':'));
    return match ? match.split(':').slice(1).join(':') : null;
  };
  const platform = getTag('AGO_AXAPLATFORM') || '';
  const app      = getTag('AGO_GLOBAL_APP') || getTag('AESM_GLOBAL_APP') || '';
  const opco     = getTag('AGO_AXAOPCOTRIGRAM') || '';

  let impact = '4';
  let urgency = '4';
  if (severity === 'AVAILABILITY') { impact = '1'; urgency = '1'; }
  else if (severity === 'INFRASTRUCTURE') { impact = '2'; urgency = '2'; }
  else if (severity === 'PERFORMANCE') { impact = '2'; urgency = '2'; }
  else if (severity === 'RESOURCE') { impact = '3'; urgency = '3'; }
  else if (severity === 'CUSTOM_ALERT') { impact = '4'; urgency = '4'; }

  const impactLabel   = `${impact} - ${impact === '1' ? 'High' : impact === '2' ? 'Medium' : 'Low'}`;
  const urgencyLabel  = `${urgency} - ${urgency === '1' ? 'High' : urgency === '2' ? 'Medium' : 'Low'}`;
  const priorityLabel = `${impact} - ${impact === '1' ? 'High' : impact === '2' ? 'Medium' : 'Low'}`;

  return {
    impact,
    urgency,
    impactLabel,
    urgencyLabel,
    priorityLabel,
    routingPriority: impact,
    problemId: esc(problemId),
    displayId: esc(displayId),
    title: esc(title),
    severity: esc(severity),
    detTime: esc(detTime),
    url: esc(url),
    description: esc(description),
    affectedNames: esc(affectedNames),
    affectedTypes: esc(affectedTypes),
    impactLevel: esc(impactLevel),
    hostName: esc(hostName),
    hostGroup: esc(hostGroup),
    platform: esc(platform),
    app: esc(app),
    opco: esc(opco)
  };
}
